import React, { useState } from "react";
import { fn, userEvent, within, expect } from "@storybook/test";

import { Button } from "../Button";
import { Input } from "../Input";
import { Stack } from "../Stack";
import { Text } from "../Text";
import { Modal } from "./Modal";

export default {
  title: "Overlay/Modal",
  component: Modal,
  tags: ["autodocs"],
  parameters: {
    layout: "padded",
    docs: {
      description: {
        component: "Modal (Dialog) component for displaying content in a layer above the page.",
      },
    },
  },
  args: {
    onOpenChange: fn(),
    onExitComplete: fn(),
  },
  argTypes: {
    size: {
      control: "select",
      options: ["xs", "sm", "md", "lg", "xl", "full"],
      description: "Size of the modal",
    },
    placement: {
      control: "select",
      options: ["top", "center", "bottom"],
      description: "Vertical placement of the modal",
    },
    scrollBehavior: {
      control: "select",
      options: ["inside", "outside"],
      description: "Scroll behavior for long content",
    },
    onOpenChange: {
      action: "open changed",
      description: "Callback when modal open state changes",
    },
    onExitComplete: {
      action: "exit complete",
      description: "Callback when modal exit animation completes",
    },
  },
};

export const Default = {
  args: {
    size: "md",
  },
  render: (args) => (
    <Modal {...args}>
      <Modal.Trigger>
        <Button>Open Modal</Button>
      </Modal.Trigger>
      <Modal.Content>
        <Modal.Header>
          <Modal.Title>Modal Title</Modal.Title>
        </Modal.Header>
        <Modal.Body>
          <Text>
            This is the modal content. You can put any content here including forms, text, images,
            etc.
          </Text>
        </Modal.Body>
        <Modal.Footer>
          <Modal.ActionTrigger>
            <Button variant="outline">Cancel</Button>
          </Modal.ActionTrigger>
          <Button>Save</Button>
        </Modal.Footer>
        <Modal.CloseTrigger />
      </Modal.Content>
    </Modal>
  ),
  play: async ({ canvasElement, args }) => {
    const canvas = within(canvasElement);
    const openButton = canvas.getByRole("button", { name: /open modal/i });

    // Click to open modal
    await userEvent.click(openButton);
    await expect(args.onOpenChange).toHaveBeenCalled();
  },
};

